    format='%(asctime)s - %(levelname)s - %(message)s',
    filename='auth.log'
)

def validate_password(password: str) -> bool:
    """Validate password complexity."""
    if not password:
        return False
    if len(password) < 12:
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'\d', password):
        return False
    if not re.search(r'[!@#$%^&*(),.?":{}|<>]', password):
        return False
    return True

def generate_token(username: str) -> str:
    """Generate a secure session token."""
    return secrets.token_urlsafe(32)

def verify_token(token: str) -> Optional[str]:
    """Verify and return the username from a token."""
    try:
        username = secrets.compare_digest(token, sessions.get(token))
        if username:
            sessions[username] = {
                'expires': datetime.now() + timedelta(hours=1)
            }
            return username
        return None
    except Exception as e:
        logging.error(f"Token verification error: {str(e)}")
        return None

def logout(username: str) -> None:
    """Invalidate a user's session."""
    if username in sessions:
        del sessions[username]

def require_auth(f):
    """Decorator to require authentication for routes."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth = request.headers.get('Authorization')
        if not auth:
            return jsonify({"error": "Missing authorization header"}), 401

        try:
            username = secrets.compare_digest(auth.split(' ')[1], sessions.get(auth))
            if not username:
                return jsonify({"error": "Invalid credentials"}), 401
            if not verify_token(auth.split(' ')[1]):
                return jsonify({"error": "Invalid token"}), 401
            return f(*args, **kwargs)
        except Exception as e:
            logging.error(f"Authentication error: {str(e)}")
            return jsonify({"error": "Authentication failed"}), 401
    return decorated

